**CODE:**
```tsx
"use client";

import { useEffect, useRef, useState } from "react";
import { X, User, Phone, Scissors, Calendar, Clock, ChevronDown } from "lucide-react";
import {
  GOOGLE_SCRIPT_URL,
  BookingFormData,
  services,
  barbers,
  timeSlots,
} from "@/data/site-data";

// ─── Types ────────────────────────────────────────────────────────────────────
type Status = "idle" | "submitting" | "success" | "error";

const EMPTY_FORM: BookingFormData = {
  name: "",
  phone: "",
  service: "",
  barber: "",
  date: "",
  time: "",
};

const REQUIRED_FIELDS: (keyof BookingFormData)[] = [
  "name", "phone", "service", "barber", "date", "time",
];

const FIELD_LABELS: Record<keyof BookingFormData, string> = {
  name: "Họ và tên",
  phone: "Số điện thoại",
  service: "Dịch vụ",
  barber: "Thợ cắt tóc",
  date: "Ngày hẹn",
  time: "Giờ hẹn",
};

// ─── Validation ───────────────────────────────────────────────────────────────
function validate(form: BookingFormData): Partial<Record<keyof BookingFormData, string>> {
  const errors: Partial<Record<keyof BookingFormData, string>> = {};

  if (!form.name.trim()) errors.name = "Vui lòng nhập họ và tên";
  else if (form.name.trim().length < 2) errors.name = "Tên phải có ít nhất 2 ký tự";

  if (!form.phone.trim()) errors.phone = "Vui lòng nhập số điện thoại";
  else if (!/^(0|\+84)[0-9]{8,9}$/.test(form.phone.trim()))
    errors.phone = "Số điện thoại không hợp lệ";

  REQUIRED_FIELDS.forEach((f) => {
    if (!form[f] && !errors[f]) errors[f] = `Vui lòng chọn ${FIELD_LABELS[f].toLowerCase()}`;
  });

  return errors;
}

// ─── Submit ───────────────────────────────────────────────────────────────────
async function submitBooking(data: BookingFormData): Promise<void> {
  if (!GOOGLE_SCRIPT_URL) throw new Error("GOOGLE_SCRIPT_URL chưa được cấu hình");

  // no-cors → opaque response; assume success if fetch doesn't throw
  await fetch(GOOGLE_SCRIPT_URL, {
    method: "POST",
    mode: "no-cors",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
}

// ─── Component ────────────────────────────────────────────────────────────────
interface BookingModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export default function BookingModal({ isOpen, onClose }: BookingModalProps) {
  const [form, setForm] = useState<BookingFormData>(EMPTY_FORM);
  const [errors, setErrors] = useState<Partial<Record<keyof BookingFormData, string>>>({});
  const [status, setStatus] = useState<Status>("idle");
  const modalRef = useRef<HTMLDivElement>(null);
  const firstFocusRef = useRef<HTMLInputElement>(null);

  // Today's date as yyyy-mm-dd for min attribute
  const todayStr = new Date().toISOString().split("T")[0];

  // Reset form when modal closes
  useEffect(() => {
    if (!isOpen) {
      setForm(EMPTY_FORM);
      setErrors({});
      setStatus("idle");
    } else {
      // Focus first field when opened
      setTimeout(() => firstFocusRef.current?.focus(), 100);
    }
  }, [isOpen]);

  // Focus trap
  useEffect(() => {
    if (!isOpen) return;
    const modal = modalRef.current;
    if (!modal) return;

    const focusable = modal.querySelectorAll<HTMLElement>(
      'button, input, select, textarea, [tabindex]:not([tabindex="-1"])'
    );
    const first = focusable[0];
    const last = focusable[focusable.length - 1];

    function handleKeyDown(e: KeyboardEvent) {
      if (e.key === "Escape") { onClose(); return; }
      if (e.key !== "Tab") return;
      if (e.shiftKey) {
        if (document.activeElement === first) { e.preventDefault(); last.focus(); }
      } else {
        if (document.activeElement === last) { e.preventDefault(); first.focus(); }
      }
    }

    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, onClose]);

  function setField<K extends keyof BookingFormData>(key: K, value: BookingFormData[K]) {
    setForm((prev) => ({ ...prev, [key]: value }));
    if (errors[key]) setErrors((prev) => ({ ...prev, [key]: undefined }));
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const validationErrors = validate(form);
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }

    setStatus("submitting");
    try {
      await submitBooking(form);
      setStatus("success");
      setTimeout(onClose, 2500);
    } catch {
      setStatus("error");
      setTimeout(() => setStatus("idle"), 3000);
    }
  }

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4"
      role="dialog"
      aria-modal="true"
      aria-labelledby="booking-modal-title"
    >
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black/70 backdrop-blur-sm"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* Modal */}
      <div
        ref={modalRef}
        className="relative w-full max-w-lg max-h-[90vh] overflow-y-auto bg-[#111] border border-[#d5b981]/30 rounded-2xl shadow-2xl"
      >
        {/* Header */}
        <div className="sticky top-0 z-10 flex items-center justify-between px-6 py-4 bg-[#111] border-b border-[#d5b981]/20">
          <h2 id="booking-modal-title" className="text-xl font-bold text-[#d5b981]">
            Đặt Lịch Cắt Tóc
          </h2>
          <button
            onClick={onClose}
            aria-label="Đóng"
            className="text-gray-400 hover:text-white transition-colors"
          >
            <X size={22} />
          </button>
        </div>

        {/* Success state */}
        {status === "success" && (
          <div className="px-6 py-12 text-center">
            <div className="text-5xl mb-4">✅</div>
            <p className="text-[#d5b981] text-lg font-semibold">Đặt lịch thành công!</p>
            <p className="text-gray-400 text-sm mt-1">Chúng tôi sẽ liên hệ xác nhận sớm nhất.</p>
          </div>
        )}

        {/* Error state */}
        {status === "error" && (
          <div className="px-6 py-4 bg-red-900/20 border-b border-red-500/30">
            <p className="text-red-400 text-sm text-center">
              Có lỗi xảy ra. Vui lòng thử lại hoặc gọi hotline.
            </p>
          </div>
        )}

        {/* Form */}
        {status !== "success" && (
          <form onSubmit={handleSubmit} className="px-6 py-4 space-y-4" noValidate>
            {/* Name */}
            <Field label="Họ và tên" icon={<User size={16} />} error={errors.name}>
              <input
                ref={firstFocusRef}
                type="text"
                placeholder="Nguyễn Văn A"
                value={form.name}
                onChange={(e) => setField("name", e.target.value)}
                aria-invalid={!!errors.name}
                className="input-field"
              />
            </Field>

            {/* Phone */}
            <Field label="Số điện thoại" icon={<Phone size={16} />} error={errors.phone}>
              <input
                type="tel"
                placeholder="0912 345 678"
                value={form.phone}
                onChange={(e) => setField("phone", e.target.value)}
                aria-invalid={!!errors.phone}
                className="input-field"
              />
            </Field>

            {/* Service */}
            <Field label="Dịch vụ" icon={<Scissors size={16} />} error={errors.service}>
              <div className="relative">
                <select
                  value={form.service}
                  onChange={(e) => setField("service", e.target.value)}
                  aria-invalid={!!errors.service}
                  className="input-field appearance-none pr-8"
                >
                  <option value="">-- Chọn dịch vụ --</option>
                  {services.map((s) => (
                    <option key={s.name} value={s.name}>{s.name} — {s.price}</option>
                  ))}
                </select>
                <ChevronDown size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
              </div>
            </Field>

            {/* Barber */}
            <Field label="Thợ cắt tóc" icon={<Scissors size={16} />} error={errors.barber}>
              <div className="relative">
                <select
                  value={form.barber}
                  onChange={(e) => setField("barber", e.target.value)}
                  aria-invalid={!!errors.barber}
                  className="input-field appearance-none pr-8"
                >
                  <option value="">-- Chọn thợ --</option>
                  {barbers.map((b) => (
                    <option key={b} value={b}>{b}</option>
                  ))}
                </select>
                <ChevronDown size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
              </div>
            </Field>

            {/* Date */}
            <Field label="Ngày hẹn" icon={<Calendar size={16} />} error={errors.date}>
              <input
                type="date"
                min={todayStr}
                value={form.date}
                onChange={(e) => setField("date", e.target.value)}
                aria-invalid={!!errors.date}
                className="input-field"
              />
            </Field>

            {/* Time grid */}
            <div>
              <label className="flex items-center gap-2 text-sm text-gray-300 mb-2">
                <Clock size={16} className="text-[#d5b981]" />
                Giờ hẹn
              </label>
              <div className="grid grid-cols-4 gap-2">
                {timeSlots.map((t) => (
                  <button
                    key={t}
                    type="button"
                    onClick={() => setField("time", t)}
                    className={`py-1.5 text-xs rounded border transition-colors ${
                      form.time === t
                        ? "bg-[#d5b981] text-black border-[#d5b981] font-semibold"
                        : "border-[#d5b981]/30 text-gray-300 hover:border-[#d5b981]/70"
                    }`}
                  >
                    {t}
                  </button>
                ))}
              </div>
              {errors.time && (
                <p className="text-red-400 text-xs mt-1">{errors.time}</p>
              )}
            </div>

            {/* Submit */}
            <button
              type="submit"
              disabled={status === "submitting"}
              className="w-full py-3 bg-[#d5b981] text-black font-bold rounded-lg hover:bg-[#e8d4a8] transition-colors disabled:opacity-60 disabled:cursor-not-allowed"
            >
              {status === "submitting" ? "Đang gửi..." : "Đặt Lịch Ngay"}
            </button>
          </form>
        )}
      </div>
    </div>
  );
}

// ─── Field wrapper ────────────────────────────────────────────────────────────
function Field({
  label, icon, error, children,
}: {
  label: string;
  icon: React.ReactNode;
  error?: string;
  children: React.ReactNode;
}) {
  return (
    <div>
      <label className="flex items-center gap-2 text-sm text-gray-300 mb-1">
        <span className="text-[#d5b981]">{icon}</span>
        {label}
      </label>
      {children}
      {error && <p className="text-red-400 text-xs mt-1" role="alert">{error}</p>}
    </div>
  );
}
```

