        await fetch(GOOGLE_SCRIPT_URL, {
          method: "POST",
          mode: "no-cors",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(formData),
        });
      }
      setStatus("success");
      setTimeout(() => {
        setStatus("idle");
        onClose();
      }, 2500);
    } catch {
      setStatus("error");
      setTimeout(() => setStatus("idle"), 3000);
    }
  };

  function setField<K extends keyof typeof EMPTY_FORM>(key: K, value: string) {
