type FormData = { name: string; phone: string; service: string; barber: string; date: string; time: string };
type FormErrors = Partial<Record<keyof FormData, string>>;

function validateForm(data: FormData): FormErrors {
  const e: FormErrors = {};
  if (!data.name.trim()) e.name = "Vui lòng nhập họ và tên";
  if (!data.phone.trim()) e.phone = "Vui lòng nhập số điện thoại";
  else if (!/^(0|\+84)[0-9]{8,9}$/.test(data.phone.trim()))
    e.phone = "Số điện thoại không hợp lệ (VD: 0912345678)";
  if (!data.service) e.service = "Vui lòng chọn dịch vụ";
  if (!data.barber) e.barber = "Vui lòng chọn thợ cắt tóc";
  if (!data.date) e.date = "Vui lòng chọn ngày";
  if (!data.time) e.time = "Vui lòng chọn giờ";
  return e;
}
```

